import { query } from '~/lib/db';
import { Result, ok, err } from '~/lib/result';

// Define internal types for clarity
type SubscriptionStatus = 'active' | 'canceled' | 'past_due' | 'unpaid' | 'trialing' | 'incomplete' | 'incomplete_expired' | 'paused';

/**
 * Records a processed webhook event ID to ensure idempotency.
 * @param eventId The unique ID of the Stripe event.
 * @returns A Result indicating success or if the event was already processed or a DB error.
 */
export async function recordProcessedEvent(eventId: string): Promise<Result<void, 'ALREADY_PROCESSED' | 'DB_ERROR'>> {
  try {
    // Attempt to insert the event ID. If it already exists (due to unique constraint),
    // the ON CONFLICT clause will prevent an error and do nothing.
    const result = await query(
      `INSERT INTO processed_webhooks (event_id, created_at)
       VALUES ($1, NOW())
       ON CONFLICT (event_id) DO NOTHING
       RETURNING event_id;`,
      [eventId]
    );

    if (result.rows.length === 0) {
      // If no row was returned, it means the event_id already existed and DO NOTHING was executed.
      return err('ALREADY_PROCESSED');
    }

    return ok(undefined);
  } catch (error) {
    console.error('Database error recording processed event:', error);
    return err('DB_ERROR');
  }
}

/**
 * Updates the status and period end of a subscription in the database.
 * @param stripeSubscriptionId The Stripe ID of the subscription.
 * @param status The new status of the subscription.
 * @param currentPeriodEnd The end date of the current billing period.
 * @returns A Result indicating success or if the subscription was not found or a DB error.
 */
export async function updateSubscriptionStatus(
  stripeSubscriptionId: string,
  status: SubscriptionStatus,
  currentPeriodEnd: Date
): Promise<Result<void, 'NOT_FOUND' | 'DB_ERROR'>> {
  try {
    const result = await query(
      `UPDATE subscriptions
       SET status = $1, current_period_end = $2, updated_at = NOW()
       WHERE stripe_subscription_id = $3;`,
      [status, currentPeriodEnd, stripeSubscriptionId]
    );

    if (result.rowCount === 0) {
      return err('NOT_FOUND');
    }

    return ok(undefined);
  } catch (error) {
    console.error('Database error updating subscription status:', error);
    return err('DB_ERROR');
  }
}

/**
 * Creates a new subscription in the database.
 * This might be called for `customer.subscription.created` events.
 * @param stripeSubscriptionId The Stripe ID of the subscription.
 * @param userId The ID of the user associated with the subscription.
 * @param status The initial status of the subscription.
 * @param currentPeriodEnd The end date of the current billing period.
 * @returns A Result indicating success or a DB error.
 */
export async function createSubscription(
  stripeSubscriptionId: string,
  userId: string, // Assuming a user ID is available or can be derived
  status: SubscriptionStatus,
  currentPeriodEnd: Date
): Promise<Result<void, 'DB_ERROR'>> {
  try {
    await query(
      `INSERT INTO subscriptions (stripe_subscription_id, user_id, status, current_period_end, created_at, updated_at)
       VALUES ($1, $2, $3, $4, NOW(), NOW());`,
      [stripeSubscriptionId, userId, status, currentPeriodEnd]
    );
    return ok(undefined);
  } catch (error) {
    console.error('Database error creating subscription:', error);
    return err('DB_ERROR');
  }
}
