  if (!stripeWebhookSecret) {
    return new Response(JSON.stringify({ error: 'Stripe webhook secret not configured.' }), {
      status: 500,
      headers: { 'Content-Type': 'application/json' },
    });
  }

  const signature = req.headers['stripe-signature'];
  if (!signature) {
    return new Response(JSON.stringify({ error: 'No Stripe-Signature header found.' }), {
      status: 400,
      headers: { 'Content-Type': 'application/json' },
    });
  }

  // Bun's Request object provides .text() for raw body
  const rawBody = await req.text();

  let event: Stripe.Event;

  try {
    event = stripe.webhooks.constructEvent(rawBody, signature, stripeWebhookSecret);
  } catch (err: any) {
    console.error(`Stripe webhook signature verification failed: ${err.message}`);
    return new Response(JSON.stringify({ error: `Webhook Error: ${err.message}` }), {
      status: 400,
      headers: { 'Content-Type': 'application/json' },
    });
  }

  // Idempotency check: record the event ID
  const recordResult = await recordProcessedEvent(event.id);
  if (recordResult.isErr() && recordResult.error === 'ALREADY_PROCESSED') {
    console.log(`Stripe event ${event.id} already processed. Skipping.`);
    return new Response(JSON.stringify({ received: true, message: 'Event already processed.' }), {
      status: 200,
      headers: { 'Content-Type': 'application/json' },
    });
