    console.error(`Database error during idempotency check for event ${event.id}:`, recordResult.error);
    return new Response(JSON.stringify({ error: 'Internal server error during idempotency check.' }), {
      status: 500,
      headers: { 'Content-Type': 'application/json' },
    });
